// invite.js — 团队邀请：签发 + 验证。token 为不透明随机串，真实数据在库里。
import { randomBytes, timingSafeEqual, createHash } from "node:crypto";

const TTL_MS = 7 * 24 * 60 * 60 * 1000; // 7天有效期

// 签发：A 邀请 email 加入 team。返回放进链接的 token。
export async function createInvite(db, { teamId, email, invitedBy }) {
  const token = randomBytes(32).toString("base64url"); // 256位，不可枚举
  const tokenHash = sha256(token); // 库里只存哈希，库泄露也无法直接用 token
  await db.run(
    `INSERT INTO invites (token_hash, team_id, email, invited_by, expires_at, status)
     VALUES (?, ?, ?, ?, ?, 'pending')`,
    [tokenHash, teamId, email.toLowerCase().trim(), invitedBy, Date.now() + TTL_MS]
  );
  return token; // 链接: /invite?token=<token>
}

// 验证：B 点链接时调用。currentUserEmail = 当前登录用户的邮箱。
// 返回 { ok, invite } 或 { ok:false, reason }。失败原因不外泄细节。
export async function verifyInvite(db, token, currentUserEmail) {
  if (typeof token !== "string" || token.length < 40) return fail("invalid");
  const row = await db.get(
    `SELECT * FROM invites WHERE token_hash = ?`,
    [sha256(token)]
  );
  if (!row) return fail("invalid");
  if (row.status !== "pending") return fail("used"); // 一次性：已接受/撤销则拒
  if (Date.now() > row.expires_at) return fail("expired");
  // 邀请绑定到具体邮箱：登录用户必须就是被邀请人，否则别人的链接用不了
  if (!emailEquals(row.email, currentUserEmail)) return fail("wrong_account");
  return { ok: true, invite: row };
}

// 接受：原子地把状态翻成 accepted，防并发重复加入（双击/重放）。
export async function acceptInvite(db, token) {
  const r = await db.run(
    `UPDATE invites SET status='accepted', accepted_at=?
     WHERE token_hash=? AND status='pending'`,
    [Date.now(), sha256(token)]
  );
  return r.changes === 1; // false = 已被别的请求抢先接受
}

function sha256(s) { return createHash("sha256").update(s).digest("hex"); }
function emailEquals(a, b) {
  const x = Buffer.from(String(a).toLowerCase().trim());
  const y = Buffer.from(String(b).toLowerCase().trim());
  return x.length === y.length && timingSafeEqual(x, y);
}
function fail(reason) { return { ok: false, reason }; }
```

